const item = $input.first();
const raw = item.json.stdout ?? item.json?.stdout ?? item.json?.output ?? (typeof item.json === 'string' ? item.json : '') ?? '';
let data = { metrics: {}, history: [] };
try {
  const str = typeof raw === 'string' ? raw : JSON.stringify(raw);
  data = JSON.parse(str.trim());
} catch (e) {
  data = { metrics: { cpu: { percent: 0 }, memory: { usedMb: 0, totalMb: 0, percent: 0 }, disk: { usedGb: 0, totalGb: 0, percent: 0 }, n8nWorkers: { active: 0, idle: 0, busy: 0, total: 0 } }, history: [] };
}
return [{ json: data }];
